public boolean isIsomorphic(String s, String t) {
    // Handle null inputs
    if (s == null || t == null) {
        return s == t;
    }

    // Handle different lengths
    if (s.length() != t.length()) {
        return false;
    }

    // Handle empty strings
    if (s.length() == 0) {
        return true;
    }

    int[] sToT = new int[256];
    int[] tToS = new int[256];
    Arrays.fill(sToT, -1);
    Arrays.fill(tToS, -1);

    for (int i = 0; i < s.length(); i++) {
        char sChar = s.charAt(i);
        char tChar = t.charAt(i);

        // Check for mapping conflicts
        if (sToT[sChar] == -1) {
            if (tToS[tChar] != -1) {
                return false; // tChar already mapped to different char
            }
            sToT[sChar] = tChar;
            tToS[tChar] = sChar;
        } else if (sToT[sChar] != tChar) {
            return false; // sChar maps to different char
        }
    }

    return true;
}
